<?php include 'includes/config.php'; require_role('admin'); if(isset($_POST['sub_id'],$_POST['status'])){$status=clean($_POST['status']);$sid=(int)$_POST['sub_id'];$pdo->prepare('UPDATE seller_subscriptions SET status=? WHERE id=?')->execute([$status,$sid]); if($status==='approved'){$s=$pdo->prepare('SELECT seller_id FROM seller_subscriptions WHERE id=?');$s->execute([$sid]);$seller=$s->fetchColumn();$pdo->prepare("UPDATE brands SET subscription_status='active', subscription_expires=DATE_ADD(CURDATE(), INTERVAL 1 YEAR) WHERE seller_id=?")->execute([$seller]);}} ?>
<!DOCTYPE html><html><head><title>Admin</title><link rel="stylesheet" href="css/styles.css"></head><body><?php include 'includes/header.php'; ?><section class="section"><h1>Admin Dashboard</h1><p class="muted">Admin can approve subscriptions and view platform activity. Seller account numbers are not shown here.</p><br><div class="dashboard"><div class="dash-card"><strong><?php echo $pdo->query('SELECT COUNT(*) FROM users WHERE role="seller"')->fetchColumn(); ?></strong>Sellers</div><div class="dash-card"><strong><?php echo $pdo->query('SELECT COUNT(*) FROM users WHERE role="buyer"')->fetchColumn(); ?></strong>Buyers</div><div class="dash-card"><strong><?php echo $pdo->query('SELECT COUNT(*) FROM products')->fetchColumn(); ?></strong>Products</div><div class="dash-card"><strong><?php echo $pdo->query('SELECT COUNT(*) FROM orders')->fetchColumn(); ?></strong>Orders</div></div><br><h2>Seller Subscriptions</h2><table class="table"><tr><th>Seller</th><th>Amount</th><th>Status</th><th>Proof</th><th>Action</th></tr><?php $stmt=$pdo->query('SELECT ss.*,u.full_name,u.email FROM seller_subscriptions ss JOIN users u ON ss.seller_id=u.id ORDER BY ss.created_at DESC');foreach($stmt as $s): ?><tr><td><?= clean($s['full_name']) ?><br><span class="muted"><?= clean($s['email']) ?></span></td><td>R<?= number_format($s['amount'],2) ?></td><td><?= clean($s['status']) ?></td><td><?php if($s['proof_path']): ?><a href="<?= clean($s['proof_path']) ?>">View proof</a><?php endif; ?></td><td><form method="post"><input type="hidden" name="sub_id" value="<?= $s['id'] ?>"><select name="status"><option>pending</option><option>approved</option><option>rejected</option></select><button>Update</button></form></td></tr><?php endforeach; ?></table></section></body></html>
